dashboard.definition:
{
	"dataSources": {
		"ds_yeZNz1VE": {
			"type": "ds.search",
			"options": {
				"query": "index=\"$index$\" source=\"$gatekeeper$\"\n| sort - _time\n| head 20\n| eval sdk_action=if(isnull(sdk_action) OR sdk_action=\"\", \"no action\", sdk_action)\n| table _time, risk_id, sdk_action, source_service, target_service, detection_type, entity_type",
				"queryParameters": {
					"sampleRatio": 1
				}
			},
			"name": "Last 20 Detections search"
		},
		"ds_SelAzXSC": {
			"type": "ds.search",
			"options": {
				"query": "index=\"$index$\" source=\"$gatekeeper$\" \n| top limit=10 target_service\n| fields target_service count\n| rename count as \"Vulnerable Target\"",
				"queryParameters": {
					"sampleRatio": 1
				}
			},
			"name": "Top 10 Most Vulnerable Target Services search"
		},
		"ds_BshSsvyM": {
			"type": "ds.search",
			"options": {
				"query": "index=\"$index$\" source=\"$gatekeeper$\" \n| stats values(source_service) as source_service by risk_id\n| top limit=10 source_service\n| fields source_service count\n| rename count as \"Vulnerable Source\"",
				"queryParameters": {
					"sampleRatio": 1
				},
				"enableSmartSources": true
			},
			"name": "Top 10 Most Vulnerable Source Services search"
		},
		"ds_Tcf1n51j": {
			"name": "Operant Actions Taken search",
			"options": {
				"query": "index=\"$index$\" source=\"$gatekeeper$\" | search (sdk_action) | stats values(sdk_action) as sdk_action by risk_id | eval sdk_action=if(sdk_action=\"\", \"no_action\", sdk_action) | chart count by sdk_action",
				"queryParameters": {
					"sampleRatio": 1
				}
			},
			"type": "ds.search"
		},
		"ds_gfg46BvG": {
			"name": "Number of Detections by Types search",
			"options": {
				"query": "index=\"$index$\" source=\"$gatekeeper$\" | stats values(entity_type) as entity_type, values(detection_type) as detection_type by risk_id | mvexpand entity_type | mvexpand detection_type | eval hierarchy = detection_type . \" > \" . entity_type | chart count by hierarchy",
				"queryParameters": {
					"sampleRatio": 1
				}
			},
			"type": "ds.search"
		},
		"ds_iH6Iy1LU": {
			"name": "Operant Detections Overview - Table search",
			"options": {
				"query": "index=\"main\" | search (sdk_action) | stats values(sdk_action) as sdk_action, values(entity_type) as entity_type, values(detection_type) as detection_type by trace_id | mvexpand entity_type | mvexpand detection_type | eval hierarchy = detection_type . \" > \" . entity_type",
				"queryParameters": {
					"earliest": "-4h@m",
					"latest": "now",
					"sampleRatio": 1
				}
			},
			"type": "ds.search"
		},
		"ds_xEDKM8L1": {
			"type": "ds.search",
			"options": {
				"enableSmartSources": true,
				"query": "index=\"main\" |  stats count by source"
			},
			"name": "List Of Gatekeepers"
		},
		"ds_07n6rdwh": {
			"type": "ds.search",
			"options": {
				"query": "| eventcount summarize=false index=* | stats count by index"
			},
			"name": "List of Indexes"
		}
	},
	"visualizations": {
		"viz_7M0xzPxF": {
			"type": "splunk.table",
			"options": {
				"count": 20,
				"dataOverlayMode": "none",
				"drilldown": "none",
				"showRowNumbers": false,
				"showInternalFields": false
			},
			"dataSources": {
				"primary": "ds_yeZNz1VE"
			},
			"title": "Last 20 Detections ($gatekeeper$)"
		},
		"viz_NSnAWZLK": {
			"type": "splunk.column",
			"options": {
				"yAxisAbbreviation": "auto",
				"y2AxisAbbreviation": "auto",
				"showRoundedY2AxisLabels": false,
				"legendTruncation": "ellipsisMiddle",
				"showY2MajorGridLines": true,
				"xAxisLabelRotation": 0,
				"xAxisTitleVisibility": "show",
				"yAxisTitleVisibility": "show",
				"y2AxisTitleVisibility": "show",
				"yAxisScale": "linear",
				"showOverlayY2Axis": false,
				"y2AxisScale": "inherit",
				"dataValuesDisplay": "off",
				"stackMode": "auto",
				"showSplitSeries": false,
				"showIndependentYRanges": false,
				"legendDisplay": "right"
			},
			"dataSources": {
				"primary": "ds_SelAzXSC"
			},
			"title": "Top 10 Most Vulnerable Target Services ($gatekeeper$)"
		},
		"viz_ODQlsp52": {
			"type": "splunk.column",
			"options": {
				"yAxisAbbreviation": "auto",
				"y2AxisAbbreviation": "auto",
				"showRoundedY2AxisLabels": false,
				"legendTruncation": "ellipsisMiddle",
				"showY2MajorGridLines": true,
				"xAxisLabelRotation": 0,
				"xAxisTitleVisibility": "show",
				"yAxisTitleVisibility": "show",
				"y2AxisTitleVisibility": "show",
				"yAxisScale": "linear",
				"showOverlayY2Axis": false,
				"y2AxisScale": "inherit",
				"dataValuesDisplay": "off",
				"stackMode": "auto",
				"showSplitSeries": false,
				"showIndependentYRanges": false,
				"legendDisplay": "right"
			},
			"dataSources": {
				"primary": "ds_BshSsvyM"
			},
			"title": "Top 10 Most Vulnerable Source Services ($gatekeeper$)"
		},
		"viz_NGa6xMqO": {
			"dataSources": {
				"primary": "ds_gfg46BvG"
			},
			"options": {
				"dataValuesDisplay": "off",
				"legendDisplay": "right",
				"legendTruncation": "ellipsisMiddle",
				"showIndependentYRanges": false,
				"showRoundedY2AxisLabels": false,
				"showSplitSeries": true,
				"showY2MajorGridLines": true,
				"stackMode": "auto",
				"xAxisTitleText": "Detection Types",
				"xAxisTitleVisibility": "show",
				"y2AxisAbbreviation": "auto",
				"y2AxisTitleVisibility": "show",
				"yAxisAbbreviation": "auto",
				"yAxisMajorTickInterval": 1,
				"yAxisMin": 0,
				"yAxisScale": "linear",
				"yAxisTitleVisibility": "show"
			},
			"title": "Number of Detections by Types ($gatekeeper$)",
			"type": "splunk.bar"
		},
		"viz_Ype7JUBH": {
			"dataSources": {
				"primary": "ds_Tcf1n51j"
			},
			"options": {
				"collapseThreshold": 0.01
			},
			"title": "Operant Actions Taken ($gatekeeper$)",
			"type": "splunk.pie"
		}
	},
	"applicationProperties": {
		"hideEdit": false,
		"hideExport": false
	},
	"inputs": {
		"input_global_trp": {
			"options": {
				"defaultValue": "-7d@h,now",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		},
		"input_gatekeeper": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "gatekeeper",
				"selectFirstSearchResult": true
			},
			"title": "Gatekeeper",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_xEDKM8L1"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"source\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"source\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			},
			"containerOptions": {
				"visibility": {}
			}
		},
		"input_6F0WbKDQ": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "index",
				"defaultValue": "main"
			},
			"title": "Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_07n6rdwh"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"index\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"index\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		}
	},
	"layout": {
		"options": {},
		"globalInputs": [
			"input_global_trp",
			"input_gatekeeper",
			"input_6F0WbKDQ"
		],
		"tabs": {
			"items": [
				{
					"label": "Overviews",
					"layoutId": "layout_1"
				}
			]
		},
		"layoutDefinitions": {
			"layout_1": {
				"options": {
					"height": 960,
					"width": 1440
				},
				"structure": [
					{
						"item": "viz_Ype7JUBH",
						"position": {
							"h": 397,
							"w": 448,
							"x": 0,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_ODQlsp52",
						"type": "block",
						"position": {
							"x": 0,
							"y": 397,
							"w": 1440,
							"h": 300
						}
					},
					{
						"item": "viz_NSnAWZLK",
						"type": "block",
						"position": {
							"x": 0,
							"y": 697,
							"w": 1440,
							"h": 300
						}
					},
					{
						"item": "viz_7M0xzPxF",
						"type": "block",
						"position": {
							"x": 0,
							"y": 997,
							"w": 1440,
							"h": 300
						}
					},
					{
						"item": "viz_NGa6xMqO",
						"position": {
							"h": 397,
							"w": 992,
							"x": 448,
							"y": 0
						},
						"type": "block"
					}
				],
				"type": "grid"
			}
		}
	},
	"title": "Operant Detections Overview",
	"description": "Operant detections, an overview of the important events",
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					}
				}
			}
		},
		"visualizations": {
			"global": {
				"showProgressBar": true
			}
		}
	}
}
